// ONE-TIME SETUP SCRIPT (local, not deployed) - replaces the placeholder
// 'PENDING_HASH' password values from supabase/migrations/0002_seed.sql
// with real bcrypt hashes, generated by this script's own bcryptjs
// (mirroring the original database/seed_passwords.php, which used PHP's
// own password_hash() for the same reason: never hand-write a hash
// string). Default password for every sample account: Passw0rd!
//
// Requires SUPABASE_URL + SUPABASE_SERVICE_ROLE_KEY in the environment.
// Run with:
//   node --env-file=.env scripts/hash-seed-passwords.mjs
// (Node 20.6+; on older Node, export the vars in your shell first.)

import { createClient } from '@supabase/supabase-js';
import bcrypt from 'bcryptjs';

const url = process.env.SUPABASE_URL;
const key = process.env.SUPABASE_SECRET_KEY || process.env.SUPABASE_SERVICE_ROLE_KEY;

if (!url || !key) {
    console.error('SUPABASE_URL and SUPABASE_SECRET_KEY must be set. See .env.example.');
    process.exit(1);
}

const supabase = createClient(url, key, { auth: { persistSession: false } });

const DEFAULT_PASSWORD = 'Passw0rd!';

async function main() {
    const hash = await bcrypt.hash(DEFAULT_PASSWORD, 10);

    const { data, error } = await supabase
        .from('users')
        .update({ password: hash })
        .eq('password', 'PENDING_HASH')
        .select('username');

    if (error) {
        console.error('Failed to seed passwords:', error.message);
        process.exit(1);
    }

    console.log(`Updated ${data.length} account(s): ${data.map((u) => u.username).join(', ')}`);
    console.log(`Default password for all sample accounts: ${DEFAULT_PASSWORD}`);
    console.log('Log in and change these immediately, especially the admin account.');
}

main();
